features.snippet:
logic [31:0] lhs1, lhs2, rhs;
always_comb lhs1 = rhs;
assign lhs2 = rhs;
always @(negedge clk) begin
  if (cond) force lhs1 = 'hdeadbeef;
  else release lhs1;
end

logic [31:0] lhs1, lhs2;
logic cond = 0;
assign lhs2 = rhs;
always @(negedge clk) begin
  if (cond) begin force lhs1 = 'h1; force lhs2 = 'h2; end
  else begin release lhs1; release lhs2; end
end

logic [31:0] sig;
logic clk;
always @(negedge clk) begin
  if (cond) force sig = 'hdeadbeef;
  else release sig;
end
